package com.example.bookservice.service;import com.example.bookservice.exception.HttpStatusException;import com.example.bookservice.model.Book;import com.example.bookservice.model.BookAdminStatsDto;import com.example.bookservice.model.BookDto;import com.example.bookservice.repository.BookRepository;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.dao.DataIntegrityViolationException;import org.springframework.http.HttpStatus;import java.util.ArrayList;import java.util.Arrays;import java.util.Collections;import java.util.List;import java.util.Optional;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.any;import static org.mockito.Mockito.*;@ExtendWith(MockitoExtension.class)class BookServiceTest {  @Mock private BookRepository bookRepository;  @InjectMocks private BookService bookService;  private Book book;  private BookDto bookDto;  @BeforeEach  void setUp() {    bookDto = new BookDto("owner1", "Book Name", "Author", "Genre", "Description");    book = new Book();    book.setId(1L);    book.setName("Book Name");    book.setAuthor("Author");    book.setGenre("Genre");    book.setDescription("Description");    book.setOwners(new ArrayList<>(Collections.singletonList("owner1")));  }  @Test  void getBooksById_ReturnBook() {    when(bookRepository.findById(1L)).thenReturn(Optional.of(book));    Book result = bookService.getBooksById(1L);    assertNotNull(result);    assertEquals(1L, result.getId());    assertEquals("Book Name", result.getName());    verify(bookRepository).findById(1L);  }  @Test  void getBooksById_Throw404Error() {    when(bookRepository.findById(1L)).thenReturn(Optional.empty());    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.getBooksById(1L));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Книга с id =  1 не найдена!", exception.getMessage());  }  @Test  void addBookOnSite_AddBook() {    when(bookRepository.save(any(Book.class))).thenReturn(book);    assertDoesNotThrow(() -> bookService.addBookOnSite(bookDto));    verify(bookRepository).save(any(Book.class));  }  @Test  void addBookOnSite_Throw409Error() {    when(bookRepository.save(any(Book.class))).thenThrow(DataIntegrityViolationException.class);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.addBookOnSite(bookDto));    assertEquals(HttpStatus.CONFLICT, exception.getHttpStatus());    assertEquals("Книга с названием Book Name уже существует!", exception.getMessage());  }  @Test  void addBookOnProfile_AddBookOwner() {    Book existingBook = new Book();    existingBook.setName("Book Name");    existingBook.setOwners(new ArrayList<>());    when(bookRepository.findByNameIgnoreCase("Book Name")).thenReturn(Optional.of(existingBook));    bookService.addBookOnProfile(bookDto);    assertTrue(existingBook.getOwners().contains("owner1"));    verify(bookRepository).save(existingBook);  }  @Test  void addBookOnProfile_Throw400Error() {    BookDto emptyDto = new BookDto();    emptyDto.setName("");    emptyDto.setOwner(null);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.addBookOnProfile(emptyDto));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Недостаточно данных!", exception.getMessage());  }  @Test  void addBookOnProfile_Throw404Error() {    when(bookRepository.findByNameIgnoreCase("Book Name")).thenReturn(Optional.empty());    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.addBookOnProfile(bookDto));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Книга с названием Book Name не найдена!", exception.getMessage());  }  @Test  void addBookOnProfile_Throw409Error() {    when(bookRepository.findByNameIgnoreCase("Book Name")).thenReturn(Optional.of(book));    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.addBookOnProfile(bookDto));    assertEquals(HttpStatus.CONFLICT, exception.getHttpStatus());    assertEquals("Книга уже привязана к профилю!", exception.getMessage());  }  @Test  void deleteOwner_RemoveOwner() {    when(bookRepository.findByNameIgnoreCase("Book Name")).thenReturn(Optional.of(book));    bookService.deleteOwner(bookDto);    assertFalse(book.getOwners().contains("owner1"));    verify(bookRepository).save(book);  }  @Test  void deleteOwner_Throw400Error() {    BookDto emptyDto = new BookDto();    emptyDto.setName("");    emptyDto.setOwner(null);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.deleteOwner(emptyDto));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Недостаточно данных!", exception.getMessage());  }  @Test  void deleteOwner_Throw404ErrorBookNotFound() {    when(bookRepository.findByNameIgnoreCase("Book Name")).thenReturn(Optional.empty());    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.deleteOwner(bookDto));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertEquals("Книга с названием  Book Name не найдена!", exception.getMessage());  }  @Test  void deleteOwner_Throw404ErrorOwnerNotFound() {    Book bookWithoutOwner = new Book();    bookWithoutOwner.setName("Book Name");    bookWithoutOwner.setOwners(new ArrayList<>());    when(bookRepository.findByNameIgnoreCase("Book Name"))        .thenReturn(Optional.of(bookWithoutOwner));    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> bookService.deleteOwner(bookDto));    assertEquals(HttpStatus.NOT_FOUND, exception.getHttpStatus());    assertTrue(exception.getMessage().contains("Владелец owner1 не привязан к книге"));  }  @Test  void getBooksByOwner_ReturnListOfBooks() {    List<Book> books = Collections.singletonList(book);    when(bookRepository.findBooksByOwner("owner1")).thenReturn(books);    List<Book> result = bookService.getBooksByOwner("owner1");    assertEquals(1, result.size());    assertEquals("Book Name", result.get(0).getName());  }  @Test  void getBooksByReady_ReturnListOfBooks() {    List<Book> books = Collections.singletonList(book);    when(bookRepository.findByOwnersIsNotEmpty()).thenReturn(books);    List<Book> result = bookService.getBooksByReady();    assertEquals(1, result.size());    assertEquals("Book Name", result.get(0).getName());  }  @Test  void getOwnersLoginById_ReturnListOfOwners() {    List<String> owners = Arrays.asList("owner1", "owner2");    when(bookRepository.findOwnersById(1L)).thenReturn(owners);    List<String> result = bookService.getOwnersLoginById(1L);    assertEquals(2, result.size());    assertTrue(result.contains("owner1"));    assertTrue(result.contains("owner2"));  }  @Test  void getBookStatsForAdmin_ReturnStats() {    when(bookRepository.count()).thenReturn(10L);    when(bookRepository.countByOwnersIsNotEmpty()).thenReturn(5L);    BookAdminStatsDto stats = bookService.getBookStatsForAdmin();    assertEquals(10L, stats.getCountBooks());    assertEquals(5L, stats.getCountReadyBooks());    assertEquals(50, stats.getPercentReady());  }  @Test  void getBookStatsForAdmin_ReturnZeroStats() {    when(bookRepository.count()).thenReturn(0L);    when(bookRepository.countByOwnersIsNotEmpty()).thenReturn(0L);    BookAdminStatsDto stats = bookService.getBookStatsForAdmin();    assertEquals(0L, stats.getCountBooks());    assertEquals(0L, stats.getCountReadyBooks());    assertEquals(0, stats.getPercentReady());  }}